// ---------------------------------------------------------------------------
// Extract and normalise the JIRA webhook payload.
// Supports both cloud (atlassian-account-id) and server (name) user formats.
// ---------------------------------------------------------------------------
const body = $input.first().json;

const eventType   = body.webhookEvent        || 'unknown';
const issueKey    = body.issue?.key          || '';
const summary     = body.issue?.fields?.summary || '';
const oldStatus   = body.changelog?.items?.find(i => i.field === 'status')?.fromString || '';
const newStatus   = body.changelog?.items?.find(i => i.field === 'status')?.toString   || body.issue?.fields?.status?.name || '';
const accountId   = body.user?.accountId     || body.user?.name || 'unknown';
const displayName = body.user?.displayName   || accountId;

// Extract GitHub PR number from JIRA issue description or custom field
// Convention: PR link stored in issue description as: PR: https://github.com/org/repo/pull/123
const description = body.issue?.fields?.description || '';
const prMatch     = description.match(/github\.com\/[^/]+\/[^/]+\/pull\/(\d+)/);
const prNumber    = prMatch ? prMatch[1] : null;

// Extract repo owner/repo from PR URL
const repoMatch   = description.match(/github\.com\/([^/]+)\/([^/]+)\/pull/);
const repoOwner   = repoMatch ? repoMatch[1] : $env.GITHUB_OWNER;
const repoName    = repoMatch ? repoMatch[2] : $env.GITHUB_REPO;

// headSha is intentionally empty: JIRA payloads do not carry Git SHAs.
// An operator can enrich this value by adding a preceding GitHub API call to
// GET /repos/{owner}/{repo}/pulls/{pull_number} and reading head.sha from the response.
// Leaving headSha empty causes the commit-status guard (Has Head SHA?) to skip
// the status POST rather than silently POST to a malformed URL.
const headSha = '';

return [{
  json: {
    eventType,
    issueKey,
    summary,
    oldStatus,
    newStatus,
    accountId,
    displayName,
    prNumber,
    repoOwner,
    repoName,
    headSha,
    rawEvent: body
  }
}];

// No-op: headSha not available — skipping commit status POST.
// To enable commit status checks, enrich headSha upstream by calling
// GET /repos/{owner}/{repo}/pulls/{pull_number} and reading head.sha.
const item = $input.first().json;
console.log(JSON.stringify({
  timestamp:   new Date().toISOString(),
  source:      'jira-to-github-sync',
  level:       'DEBUG',
  message:     'headSha empty — skipping commit status POST',
  jira_ticket: item.issueKey,
  prNumber:    item.prNumber
}));
return [{ json: { skipped: true, reason: 'no_head_sha', issueKey: item.issueKey } }];

// ---------------------------------------------------------------------------
// Build a structured log entry for every processed event.
// This output can be forwarded to an audit log / S3 / Splunk.
// ---------------------------------------------------------------------------
const now = new Date().toISOString();
const item = $input.first().json;

const logEntry = {
  timestamp:  now,
  source:     'jira-to-github-sync',
  jira_ticket: item.issueKey  || 'N/A',
  github_pr:  item.prNumber   || 'N/A',
  action:     `status_changed:${item.oldStatus} → ${item.newStatus}`,
  user:       item.displayName || item.accountId || 'unknown',
  repo:       `${item.repoOwner}/${item.repoName}`,
  level:      'INFO'
};

console.log(JSON.stringify(logEntry));
return [{ json: logEntry }];

// ---------------------------------------------------------------------------
// No-op: JIRA status not mapped to a GitHub action.
// Log and exit cleanly so the webhook returns 200.
// ---------------------------------------------------------------------------
const item = $input.first().json;
console.log(JSON.stringify({
  timestamp:   new Date().toISOString(),
  source:      'jira-to-github-sync',
  level:       'DEBUG',
  message:     'Unhandled status — no GitHub action taken',
  jira_ticket: item.issueKey,
  newStatus:   item.newStatus
}));
return [{ json: { skipped: true, reason: 'unmapped_status', newStatus: item.newStatus } }];

// ---------------------------------------------------------------------------
// No PR number found: log and stop. Webhook still returns 200.
// ---------------------------------------------------------------------------
const item = $input.first().json;
console.log(JSON.stringify({
  timestamp:   new Date().toISOString(),
  source:      'jira-to-github-sync',
  level:       'WARN',
  message:     'No GitHub PR number in JIRA issue description — skipping',
  jira_ticket: item.issueKey
}));
return [{ json: { skipped: true, reason: 'no_pr_number', issueKey: item.issueKey } }];

// ---------------------------------------------------------------------------
// Error handler — catches failures from any upstream node.
// Emits a structured error log and (optionally) sends a Slack/email alert.
// ---------------------------------------------------------------------------
const error = $input.first().json;
console.error(JSON.stringify({
  timestamp: new Date().toISOString(),
  source:    'jira-to-github-sync',
  level:     'ERROR',
  message:   error.message || 'Unknown error',
  node:      error.node    || 'unknown',
  details:   error
}));
// Re-throw so n8n marks the execution as failed
throw new Error(`[jira-to-github-sync] ${error.message || 'Workflow error'}`);
